function crc16(str: string): string {
  let crc = 0xffff;
  for (let i = 0; i < str.length; i++) {
    crc ^= str.charCodeAt(i) << 8;
    for (let j = 0; j < 8; j++) {
      crc = crc & 0x8000 ? (crc << 1) ^ 0x1021 : crc << 1;
      crc &= 0xffff;
    }
  }
  return crc.toString(16).toUpperCase().padStart(4, "0");
}
function tlv(id: string, val: string): string {
  return id + String(val.length).padStart(2, "0") + val;
}
function buildPix(key: string, name: string, city: string): string {
  const mai = tlv("26", tlv("00", "br.gov.bcb.pix") + tlv("01", key));
  let p =
    tlv("00", "01") + mai + tlv("52", "0000") + tlv("53", "986") +
    tlv("58", "BR") + tlv("59", name) + tlv("60", city) +
    tlv("62", tlv("05", "***"));
  p += "6304";
  return p + crc16(p);
}
